package dark.phoenix.app;

import dark.phoenix.list.LinkedList;

import static dark.phoenix.utilities.StringUtils.join;
import static dark.phoenix.utilities.StringUtils.split;
import static dark.phoenix.app.MessageUtils.getMessage;

import org.apache.commons.text.WordUtils;

public class App {
    public static void main(String[] args) {
        LinkedList tokens;
        tokens = split(getMessage());
        String result = join(tokens);
        System.out.println(WordUtils.capitalize(result));
    }
}
